import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Reports & AI Summaries","description":"Generate AI-written summaries of incidents over a selected time range for briefings and postmortems.","frontmatter":{"title":"Reports & AI Summaries","description":"Generate AI-written summaries of incidents over a selected time range for briefings and postmortems."},"headers":[],"relativePath":"portals/drm/reports.md","filePath":"portals/drm/reports.md"}'),n={name:"portals/drm/reports.md"};function s(o,e,m,l,c,d){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="reports-ai-summaries" tabindex="-1">Reports &amp; AI Summaries <a class="header-anchor" href="#reports-ai-summaries" aria-label="Permalink to &quot;Reports &amp; AI Summaries&quot;">​</a></h1><p><strong>Route:</strong> <code>/drm/reports</code> · <strong>Edition:</strong> Community+ (AI generation requires OpenAI config)</p><p>The Reports section generates human-readable summaries of incidents over a selected time range. Summaries are written by an AI assistant and can be used as executive briefings, postmortem starters, or customer communications.</p><h2 id="generating-a-summary" tabindex="-1">Generating a summary <a class="header-anchor" href="#generating-a-summary" aria-label="Permalink to &quot;Generating a summary&quot;">​</a></h2><ol><li>Select a date range (e.g. &quot;last 7 days&quot; or a custom range)</li><li>Click <strong>Preview</strong> to see which incidents will be included</li><li>Click <strong>Generate</strong> — the AI analyses all matched incidents and writes a structured report</li><li>The report is saved and appears in the summaries list</li></ol><h2 id="summary-content" tabindex="-1">Summary content <a class="header-anchor" href="#summary-content" aria-label="Permalink to &quot;Summary content&quot;">​</a></h2><p>A generated summary typically includes:</p><ul><li>Total incident count by severity</li><li>Top affected products</li><li>Notable incidents with brief descriptions</li><li>Common root causes and themes</li><li>Recommended preventive actions</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>AI summaries use the OpenAI connection configured under <strong>Portal Config → AI Settings</strong>. If no AI config is present, the Generate button is disabled and a prompt to configure it is shown.</p>',10)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
